//! Minimal `AndroidManifest.xml` emitter for the Kotlin Android mode.

use alef_core::config::ResolvedCrateConfig;

/// Emit a minimal `AndroidManifest.xml` for an Android library module.
pub(crate) fn emit(config: &ResolvedCrateConfig) -> String {
    let package = config.kotlin_package();
    format!(
        r#"<?xml version="1.0" encoding="utf-8"?>
<!-- Generated by alef. Do not edit by hand. -->
<manifest xmlns:android="http://schemas.android.com/apk/res/android"
    package="{package}">
</manifest>
"#
    )
}
